import { Team } from '../team';
import { TeamPlanStatus, BallUsageStatus, AiCoachUsageStatus } from '../team-status';

// ========== Test Helper Functions ==========

/**
 * 日付計算ヘルパー
 */
const daysFromNow = (days: number): string => {
  return new Date(Date.now() + days * 24 * 60 * 60 * 1000).toISOString();
};

/**
 * TeamPlan データのデフォルト値を持つビルダー
 */
const createTeamPlanData = (overrides: any = {}) => ({
  id: 'plan1',
  teamId: 'team1',
  planId: 1,
  plan: {
    id: 1,
    name: 'Standard',
    maxBalls: 100,
    maxMembers: 10,
    maxAiCoachs: 5,
    pricePerMonth: 1000,
    ...overrides.plan,
  },
  startDate: daysFromNow(-10),
  endDate: daysFromNow(20),
  currentUsage: 30,
  currentAiCoachUsage: 2,
  isActive: true,
  subscriptionType: null,
  createdAt: new Date().toISOString(),
  updatedAt: new Date().toISOString(),
  ...overrides,
});

/**
 * Item データのデフォルト値を持つビルダー
 */
const createItemData = (overrides: any = {}) => ({
  id: 'item1',
  teamId: 'team1',
  ballUsage: 15,
  ballAvailableCount: 50,
  aiCoachUsage: 3,
  aiCoachAvailableCount: 10,
  createdAt: new Date().toISOString(),
  updatedAt: new Date().toISOString(),
  ...overrides,
});

/**
 * Team インスタンスを作成するヘルパー
 * @param overrides - 上書きしたいプロパティ
 * @returns Team インスタンス
 */
const createTeam = (overrides: any = {}): Team => {
  return new Team({
    id: 'team1',
    imageUrl: null,
    presignedImageUrl: null,
    name: 'Test Team',
    ownerUserId: 'user1',
    teamType: 'multi',
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
    deletionScheduledAt: null,
    teamPlan: null,
    nextTeamPlan: null,
    users: [],
    billingFailureReason: null,
    teamPlanCancelAt: null,
    teamPlanDowngradeAt: null,
    downgradePlanId: null,
    item: null,
    ...overrides,
  });
};

// ========== Tests ==========

describe('Team', () => {
  describe('ballRate', () => {
    it('maxBalls が 0 の場合は 0 を返す', () => {
      const team = createTeam();
      expect(team.ballRate).toBe(0);
    });

    it('使用量が 0 の場合は 0 を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData({ currentUsage: 0 }),
      });
      expect(team.ballRate).toBe(0);
    });

    it('使用量が 50% の場合は 0.5 を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData({ currentUsage: 50 }),
      });
      expect(team.ballRate).toBe(0.5);
    });

    it('使用量が 100% の場合は 1.0 を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData({ currentUsage: 100 }),
      });
      expect(team.ballRate).toBe(1.0);
    });

    it('currentUsage が maxBalls を超えている場合でもクランプされて 1.0 を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData({ currentUsage: 150 }),
      });
      expect(team.ballRate).toBe(1.0);
    });
  });

  describe('remainingDays', () => {
    it('teamPlan が null の場合は 0 を返す', () => {
      const team = createTeam();
      expect(team.remainingDays).toBe(0);
    });

    it('teamPlan の isActive が false の場合は 0 を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData({ isActive: false }),
      });
      expect(team.remainingDays).toBe(0);
    });

    it('期限切れの場合は 0 を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData({
          startDate: daysFromNow(-40),
          endDate: daysFromNow(-10),
        }),
      });
      expect(team.remainingDays).toBe(0);
    });

    it('有効なプランがある場合は残り日数を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData(),
      });
      expect(team.remainingDays).toBeGreaterThanOrEqual(19);
      expect(team.remainingDays).toBeLessThan(21);
    });
  });

  describe('ballUsage', () => {
    it('teamPlan も item も null の場合は 0 を返す', () => {
      const team = createTeam();
      expect(team.ballUsage).toBe(0);
    });

    it('teamPlan のみ有効な場合は teamPlan の currentUsage を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData(),
      });
      expect(team.ballUsage).toBe(30);
    });

    it('item のみ有効な場合は item の ballUsage を返す', () => {
      const team = createTeam({
        item: createItemData(),
      });
      expect(team.ballUsage).toBe(15);
    });

    it('teamPlan と item が両方有効な場合は合算を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData(),
        item: createItemData(),
      });
      expect(team.ballUsage).toBe(45); // 30 + 15
    });

    it('teamPlan が期限切れの場合は item のみの値を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData({
          startDate: daysFromNow(-40),
          endDate: daysFromNow(-10),
        }),
        item: createItemData(),
      });
      expect(team.ballUsage).toBe(15);
    });

    it('teamPlan の currentUsage が maxBalls を超えている場合は maxBalls でクランプする', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData({ currentUsage: 150 }),
      });
      expect(team.ballUsage).toBe(100);
    });

    it('item の ballUsage が ballAvailableCount を超えている場合は ballAvailableCount でクランプする', () => {
      const team = createTeam({
        item: createItemData({ ballUsage: 80 }),
      });
      expect(team.ballUsage).toBe(50);
    });

    it('teamPlan と item の両方で上限を超えている場合は両方クランプして合算する', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData({ currentUsage: 150 }),
        item: createItemData({ ballUsage: 80 }),
      });
      expect(team.ballUsage).toBe(150); // 100 + 50
    });
  });

  describe('maxBalls', () => {
    it('teamPlan も item も null の場合は 0 を返す', () => {
      const team = createTeam();
      expect(team.maxBalls).toBe(0);
    });

    it('teamPlan のみ有効な場合は teamPlan の maxBalls を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData(),
      });
      expect(team.maxBalls).toBe(100);
    });

    it('item のみ有効な場合は item の ballAvailableCount を返す', () => {
      const team = createTeam({
        item: createItemData(),
      });
      expect(team.maxBalls).toBe(50);
    });

    it('teamPlan と item が両方有効な場合は合算を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData(),
        item: createItemData(),
      });
      expect(team.maxBalls).toBe(150); // 100 + 50
    });

    it('teamPlan が期限切れの場合は item のみの値を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData({
          startDate: daysFromNow(-40),
          endDate: daysFromNow(-10),
        }),
        item: createItemData(),
      });
      expect(team.maxBalls).toBe(50);
    });
  });

  describe('teamPlanStatus', () => {
    it('teamPlan が null の場合は NO_CONTRACT を返す', () => {
      const team = createTeam();
      expect(team.teamPlanStatus).toBe(TeamPlanStatus.NO_CONTRACT);
    });

    it('teamPlan の isActive が false の場合は NO_CONTRACT を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData({ isActive: false }),
      });
      expect(team.teamPlanStatus).toBe(TeamPlanStatus.NO_CONTRACT);
    });

    it('期限切れで nextTeamPlan が保留中の場合は NEXT_PLAN_PENDING を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData({
          startDate: daysFromNow(-40),
          endDate: daysFromNow(-10),
        }),
        nextTeamPlan: {
          id: 'plan2',
          teamId: 'team1',
          planId: 2,
          plan: {
            id: 2,
            name: 'Premium',
            maxBalls: 200,
            maxMembers: 20,
            maxAiCoachs: 10,
            pricePerMonth: 2000,
          },
          isPendingActivation: true,
          createdAt: new Date().toISOString(),
          updatedAt: new Date().toISOString(),
        },
      });
      expect(team.teamPlanStatus).toBe(TeamPlanStatus.NEXT_PLAN_PENDING);
    });

    it('期限切れの場合は EXPIRED を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData({
          startDate: daysFromNow(-40),
          endDate: daysFromNow(-10),
        }),
      });
      expect(team.teamPlanStatus).toBe(TeamPlanStatus.EXPIRED);
    });

    it('残り 30 日以内の場合は EXPIRING_SOON を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData(),
      });
      expect(team.teamPlanStatus).toBe(TeamPlanStatus.EXPIRING_SOON);
    });

    it('残り 31 日以上の場合は OK を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData({
          startDate: daysFromNow(-10),
          endDate: daysFromNow(40),
        }),
      });
      expect(team.teamPlanStatus).toBe(TeamPlanStatus.OK);
    });
  });

  describe('ballUsageStatus', () => {
    it('使用量が上限に達している場合は LIMIT_REACHED を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData({
          currentUsage: 100,
          endDate: daysFromNow(40),
        }),
      });
      expect(team.ballUsageStatus).toBe(BallUsageStatus.LIMIT_REACHED);
    });

    it('使用量が上限を超えている場合は LIMIT_REACHED を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData({
          currentUsage: 105,
          endDate: daysFromNow(40),
        }),
      });
      expect(team.ballUsageStatus).toBe(BallUsageStatus.LIMIT_REACHED);
    });

    it('使用量が 90% 以上の場合は LIMIT_APPROACHING を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData({
          currentUsage: 90,
          endDate: daysFromNow(40),
        }),
      });
      expect(team.ballUsageStatus).toBe(BallUsageStatus.LIMIT_APPROACHING);
    });

    it('使用量が 90% 未満の場合は OK を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData({
          currentUsage: 50,
          endDate: daysFromNow(40),
        }),
      });
      expect(team.ballUsageStatus).toBe(BallUsageStatus.OK);
    });

    it('maxBalls が 0 の場合は LIMIT_REACHED を返す', () => {
      const team = createTeam();
      expect(team.ballUsageStatus).toBe(BallUsageStatus.LIMIT_REACHED);
    });
  });

  describe('canAnalyzeBall', () => {
    it('ballUsageStatus が OK の場合は true を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData({
          currentUsage: 50,
          endDate: daysFromNow(40),
        }),
      });
      expect(team.canAnalyzeBall).toBe(true);
    });

    it('ballUsageStatus が LIMIT_APPROACHING の場合は true を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData({
          currentUsage: 90,
          endDate: daysFromNow(40),
        }),
      });
      expect(team.canAnalyzeBall).toBe(true);
    });

    it('ballUsageStatus が LIMIT_REACHED の場合は false を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData({
          currentUsage: 100,
          endDate: daysFromNow(40),
        }),
      });
      expect(team.canAnalyzeBall).toBe(false);
    });

    it('teamPlan が期限切れでも item が有効なら true を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData({
          startDate: daysFromNow(-40),
          endDate: daysFromNow(-10),
        }),
        item: createItemData(),
      });
      expect(team.canAnalyzeBall).toBe(true);
      expect(team.teamPlanStatus).toBe(TeamPlanStatus.EXPIRED);
    });
  });

  describe('maxAiCoachCount', () => {
    it('teamPlan も item も null の場合は 0 を返す', () => {
      const team = createTeam();
      expect(team.maxAiCoachCount).toBe(0);
    });

    it('teamPlan のみ有効な場合は teamPlan の maxAiCoachs を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData(),
      });
      expect(team.maxAiCoachCount).toBe(5);
    });

    it('item のみ有効な場合は item の aiCoachAvailableCount を返す', () => {
      const team = createTeam({
        item: createItemData(),
      });
      expect(team.maxAiCoachCount).toBe(10);
    });

    it('teamPlan と item が両方有効な場合は合算を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData(),
        item: createItemData(),
      });
      expect(team.maxAiCoachCount).toBe(15); // 5 + 10
    });

    it('teamPlan が期限切れの場合は item のみの値を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData({
          startDate: daysFromNow(-40),
          endDate: daysFromNow(-10),
        }),
        item: createItemData(),
      });
      expect(team.maxAiCoachCount).toBe(10);
    });
  });

  describe('aiCoachUsageStatus', () => {
    it('使用量が上限に達している場合は LIMIT_REACHED を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData({
          currentAiCoachUsage: 5,
          endDate: daysFromNow(40),
        }),
      });
      expect(team.aiCoachUsageStatus).toBe(AiCoachUsageStatus.LIMIT_REACHED);
    });

    it('使用量が 90% 以上の場合は LIMIT_APPROACHING を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData({
          plan: { maxAiCoachs: 10 },
          currentAiCoachUsage: 9,
          endDate: daysFromNow(40),
        }),
      });
      expect(team.aiCoachUsageStatus).toBe(AiCoachUsageStatus.LIMIT_APPROACHING);
    });

    it('使用量が 90% 未満の場合は OK を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData({
          currentAiCoachUsage: 2,
          endDate: daysFromNow(40),
        }),
      });
      expect(team.aiCoachUsageStatus).toBe(AiCoachUsageStatus.OK);
    });

    it('teamPlan の currentAiCoachUsage が maxAiCoachs を超えている場合は maxAiCoachs でクランプする', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData({ currentAiCoachUsage: 10 }),
      });
      expect(team.aiCoachUsage).toBe(5);
    });

    it('item の aiCoachUsage が aiCoachAvailableCount を超えている場合は aiCoachAvailableCount でクランプする', () => {
      const team = createTeam({
        item: createItemData({ aiCoachUsage: 20 }),
      });
      expect(team.aiCoachUsage).toBe(10);
    });

    it('teamPlan と item の AI コーチ使用量が両方上限を超えている場合は両方クランプして合算する', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData({ currentAiCoachUsage: 10 }),
        item: createItemData({ aiCoachUsage: 20 }),
      });
      expect(team.aiCoachUsage).toBe(15); // 5 + 10
    });
  });

  describe('canUseAiCoach', () => {
    it('aiCoachUsageStatus が OK の場合は true を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData({
          currentAiCoachUsage: 2,
          endDate: daysFromNow(40),
        }),
      });
      expect(team.canUseAiCoach).toBe(true);
    });

    it('aiCoachUsageStatus が LIMIT_APPROACHING の場合は true を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData({
          plan: { maxAiCoachs: 10 },
          currentAiCoachUsage: 9,
          endDate: daysFromNow(40),
        }),
      });
      expect(team.canUseAiCoach).toBe(true);
    });

    it('aiCoachUsageStatus が LIMIT_REACHED の場合は false を返す', () => {
      const team = createTeam({
        teamPlan: createTeamPlanData({
          currentAiCoachUsage: 5,
          endDate: daysFromNow(40),
        }),
      });
      expect(team.canUseAiCoach).toBe(false);
    });
  });
});
